import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./studentDashboard.css";

const StudentDashboard = () => {
  const navigate = useNavigate();

  /* ---------- AUTH ---------- */
  const token   = localStorage.getItem("token");
  const userId  = localStorage.getItem("userId");   // sno
  const role    = localStorage.getItem("role");

  /* ---------- STATE ---------- */
  const [activeTab, setActiveTab] = useState("overview");
  const [profile, setProfile]   = useState({});
  const [mentors, setMentors]   = useState([]);
  const [error, setError]       = useState("");

  /* ---------- FETCHERS ---------- */
  const fetchProfile = async () => {
    try {
      const res = await fetch(`http://localhost:5050/api/students/me`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Failed");
      setProfile(data);
    } catch (e) { setError(e.message); }
  };

  const fetchMentors = async () => {
    try {
      const res = await fetch(`http://localhost:5050/api/students/mentors`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Failed");
      setMentors(data);
    } catch (e) { setError(e.message); }
  };

  /* ---------- EFFECT ---------- */
  useEffect(() => {
    if (!token || role !== "student") {
      navigate("/login");
      return;
    }
    fetchProfile();
    fetchMentors();
  }, [token, role, navigate]);

  /* ---------- LOGOUT ---------- */
  const handleLogout = () => {
    localStorage.clear();
    navigate("/login");
  };

  /* ---------- RENDER ---------- */
  return (
    <div className="student-dashboard">
      {/* ────── HEADER ────── */}
      <div className="dashboard-header">
        <h1>Student Dashboard</h1>
        <button className="logout-btn" onClick={handleLogout}>
          Logout
        </button>
      </div>

      {/* ────── TABS ────── */}
      <div className="tab-buttons">
        <button
          className={activeTab === "overview" ? "active" : ""}
          onClick={() => setActiveTab("overview")}
        >
          Overview
        </button>
        <button
          className={activeTab === "mentors" ? "active" : ""}
          onClick={() => setActiveTab("mentors")}
        >
          Mentors
        </button>
        {/* add more tabs later */}
      </div>

      {/* ────── ERROR ────── */}
      {error && <p className="error-banner">{error}</p>}

      {/* ────── OVERVIEW TAB ────── */}
      {activeTab === "overview" && (
        <div className="overview-tab">
          <h2>Welcome, {profile.studentname || "Student"}!</h2>
          <div className="overview-sections">
            <div className="section-card">
              <h3>Profile</h3>
              <p><strong>Email:</strong> {profile.Email}</p>
              <p><strong>Semester:</strong> {profile.semester}</p>
              <p><strong>Section:</strong> {profile.section}</p>
            </div>
          </div>
        </div>
      )}

      {/* ────── MENTORS TAB ────── */}
      {activeTab === "mentors" && (
        <div className="mentors-tab">
          <h2>All Mentors</h2>
          {mentors.length === 0 ? (
            <p>No mentors available.</p>
          ) : (
            <div className="mentors-container">
              {mentors.map((m) => (
                <div key={m.sno} className="mentor-card">
                  <h3>{m.facultyname}</h3>
                  <p><strong>Specialization:</strong> {m.specialization}</p>
                  <p><strong>Email:</strong> {m.Email}</p>
                  <button onClick={() => alert(`Select ${m.facultyname}`)}>
                    Select Mentor
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default StudentDashboard;
